import sys

def main():
    N, K = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    empty_seats = K
    starts = 0

    while A:
        if empty_seats >= A[0]:
            empty_seats -= A[0]
            A.pop(0)
        else:
            starts += 1
            empty_seats = K

    # After processing all groups, if there are still people in the attraction, start once more
    if empty_seats < K:
        starts += 1

    print(starts)

if __name__ == "__main__":
    main()
